function solve(c: number, connections: number[][], queries: number[][]): number[] {
    // Build the graph
    const graph: number[][] = Array.from({ length: c + 1 }, () => []);
    for (const [u, v] of connections) {
        graph[u].push(v);
        graph[v].push(u);
    }

    // Union-Find (Disjoint Set Union) data structure
    class DSU {
        parent: number[];
        rank: number[];
        constructor(size: number) {
            this.parent = Array.from({ length: size + 1 }, (_, i) => i);
            this.rank = Array.from({ length: size + 1 }, () => 1);
        }

        find(u: number): number {
            if (this.parent[u] !== u) {
                this.parent[u] = this.find(this.parent[u]);
            }
            return this.parent[u];
        }

        union(u: number, v: number): boolean {
            const rootU = this.find(u);
            const rootV = this.find(v);
            if (rootU === rootV) return false;
            if (this.rank[rootU] < this.rank[rootV]) {
                this.parent[rootU] = rootV;
            } else {
                this.parent[rootV] = rootU;
                if (this.rank[rootU] === this.rank[rootV]) {
                    this.rank[rootU]++;
                }
            }
            return true;
        }
    }

    // Initialize DSU
    const dsu = new DSU(c);
    for (const [u, v] of connections) {
        dsu.union(u, v);
    }

    // Keep track of online stations
    const online: Set<number> = new Set();
    for (let i = 1; i <= c; i++) {
        online.add(i);
    }

    // For each root, keep track of the minimum node in its set
    const minInSet: Map<number, number> = new Map();
    for (let i = 1; i <= c; i++) {
        minInSet.set(dsu.find(i), i);
    }

    const result: number[] = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            if (online.has(x)) {
                result.push(x);
            } else {
                const root = dsu.find(x);
                const minNode = minInSet.get(root);
                if (minNode !== undefined && online.has(minNode)) {
                    result.push(minNode);
                } else {
                    result.push(-1);
                }
            }
        } else {
            // x goes offline
            online.delete(x);
        }
    }

    return result;
}

