def solve(c: int, connections: List[List[int]], queries: List[List[int]]) -> List[int]:
    # Build the graph
    graph = [[] for _ in range(c + 1)]
    for u, v in connections:
        graph[u].append(v)
        graph[v].append(u)

    # Union-Find (Disjoint Set Union) data structure
    class DSU:
        def __init__(self, size: int):
            self.parent = list(range(size + 1))
            self.rank = [1] * (size + 1)

        def find(self, u: int) -> int:
            if self.parent[u] != u:
                self.parent[u] = self.find(self.parent[u])
            return self.parent[u]

        def union(self, u: int, v: int) -> bool:
            root_u = self.find(u)
            root_v = self.find(v)
            if root_u == root_v:
                return False
            if self.rank[root_u] < self.rank[root_v]:
                self.parent[root_u] = root_v
            else:
                self.parent[root_v] = root_u
                if self.rank[root_u] == self.rank[root_v]:
                    self.rank[root_u] += 1
            return True

    # Initialize DSU
    dsu = DSU(c)
    for u, v in connections:
        dsu.union(u, v)

    # Keep track of online stations
    online: Set[int] = set(range(1, c + 1))

    # For each root, keep track of the minimum node in its set
    min_in_set: dict[int, int] = {}
    for i in range(1, c + 1):
        root = dsu.find(i)
        if root not in min_in_set:
            min_in_set[root] = i

    result: List[int] = []

    for query in queries:
        if query[0] == 1:
            x = query[1]
            if x in online:
                result.append(x)
            else:
                root = dsu.find(x)
                min_node = min_in_set.get(root)
                if min_node is not None and min_node in online:
                    result.append(min_node)
                else:
                    result.append(-1)
        else:
            # x goes offline
            online.discard(query[1])

    return result
